// ============================================================
// WF-REMINDER: Recordatorios de turno 24hs antes
// Corre cada hora. Envía turno_recordatorio a pacientes con turno mañana.
// recordatorio_enviado=true evita duplicados.
// ============================================================

const helpers = this.helpers;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const WA_TOKEN = $env.META_WHATSAPP_TOKEN;
const PHONE_ID = $env.WA_PHONE_NUMBER_ID;
const TG_BOT_TOKEN = '8736535917:AAEgHkDacG5kPaKSGIJa4dR0XjJNhIkaX0U';
const TG_CHAT_ID = '6343825256';
const OFFSET_ART = -3 * 60 * 60 * 1000;

const DIAS = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];

async function supaFetch(path) {
  return await helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/${path}`,
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
  });
}

async function supaUpdate(table, filters, data) {
  await helpers.httpRequest({
    method: 'PATCH',
    url: `${SUPABASE_URL}/rest/v1/${table}?${filters}`,
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify(data)
  });
}

async function sendTemplate(phone, templateName, bodyParams) {
  const resp = await helpers.httpRequest({
    method: 'POST',
    url: `https://graph.facebook.com/v21.0/${PHONE_ID}/messages`,
    headers: { 'Authorization': `Bearer ${WA_TOKEN}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      messaging_product: 'whatsapp',
      to: phone,
      type: 'template',
      template: {
        name: templateName,
        language: { code: 'es_AR' },
        components: [{ type: 'body', parameters: bodyParams.map(t => ({ type: 'text', text: String(t) })) }]
      }
    })
  });
  if (!resp?.messages?.length) throw new Error('Template send failed: ' + JSON.stringify(resp));
  return resp;
}

function formatPhone(phone) {
  if (!phone) return '';
  let p = phone.replace(/[^0-9]/g, '');
  if (p.startsWith('54') && p.length >= 12) return p;
  if (p.startsWith('9') && p.length >= 10) return '54' + p;
  if (p.length === 10) return '549' + p;
  return p;
}

async function alertTelegram(msg) {
  try {
    await helpers.httpRequest({
      method: 'POST',
      url: `https://api.telegram.org/bot${TG_BOT_TOKEN}/sendMessage`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ chat_id: TG_CHAT_ID, text: msg, parse_mode: 'HTML' })
    });
  } catch(e) {}
}

// Guard: permite deshabilitar recordatorios desde EasyPanel sin tocar código
if ($env.RECORDATORIOS_HABILITADOS === 'false') {
  return [{ json: { action: 'disabled', reason: 'RECORDATORIOS_HABILITADOS=false' } }];
}

// Calcular rango "mañana" en ART (UTC-3)
const now = new Date();
const nowART = new Date(now.getTime() + OFFSET_ART);
const tomorrowART = new Date(nowART);
tomorrowART.setDate(tomorrowART.getDate() + 1);
tomorrowART.setHours(0, 0, 0, 0);
const startUTC = new Date(tomorrowART.getTime() - OFFSET_ART);
const endUTC = new Date(startUTC.getTime() + 24 * 60 * 60 * 1000);

// Buscar turnos de mañana sin recordatorio
const turnos = await supaFetch(
  `consultorio_turnos?fecha_hora=gte.${startUTC.toISOString()}&fecha_hora=lt.${endUTC.toISOString()}&estado=in.(agendado,confirmado)&recordatorio_enviado=is.false&select=id,fecha_hora,paciente_id,profesional_id`
);

if (!turnos?.length) {
  return [{ json: { action: 'no_reminders', fecha: tomorrowART.toISOString().slice(0, 10) } }];
}

// Obtener pacientes y profesionales en batch
const pacIds = [...new Set(turnos.map(t => t.paciente_id))];
const profIds = [...new Set(turnos.map(t => t.profesional_id))];

const [pacientes, profesionales] = await Promise.all([
  supaFetch(`consultorio_pacientes?id=in.(${pacIds.join(',')})&select=id,nombre,telefono_wa`),
  supaFetch(`consultorio_profesionales?id=in.(${profIds.join(',')})&select=id,nombre`)
]);

const pacMap = {};
(pacientes || []).forEach(p => { pacMap[p.id] = p; });
const profMap = {};
(profesionales || []).forEach(p => { profMap[p.id] = p; });

// Enviar recordatorios
let enviados = 0, fallidos = 0;

for (const turno of turnos) {
  const paciente = pacMap[turno.paciente_id];
  const profesional = profMap[turno.profesional_id];
  if (!paciente?.telefono_wa) { fallidos++; continue; }

  const fechaHora = new Date(turno.fecha_hora);
  const fechaART = new Date(fechaHora.getTime() + OFFSET_ART);
  const fechaDisplay = `${DIAS[fechaART.getDay()]} ${String(fechaART.getDate()).padStart(2,'0')}/${String(fechaART.getMonth()+1).padStart(2,'0')}`;
  const horaDisplay = `${String(fechaART.getHours()).padStart(2,'0')}:${String(fechaART.getMinutes()).padStart(2,'0')}`;
  const primerNombre = paciente.nombre.split(' ')[0];
  const nombreMedico = profesional?.nombre || 'tu médico';

  try {
    await sendTemplate(
      formatPhone(paciente.telefono_wa),
      'turno_recordatorio',
      [primerNombre, fechaDisplay, horaDisplay, nombreMedico]
    );
    await supaUpdate('consultorio_turnos', `id=eq.${turno.id}`, { recordatorio_enviado: true });

    // Setear estado para que el paciente responda en contexto del recordatorio
    try {
      const convRes = await helpers.httpRequest({
        method: 'GET',
        url: `${SUPABASE_URL}/rest/v1/consultorio_conversaciones`,
        qs: { telefono_wa: `eq.${formatPhone(paciente.telefono_wa)}`, select: 'id,estado,handoff_humano', limit: '1' },
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
      });
      const convActual = convRes?.[0];
      const ESTADOS_PRIORITARIOS = ['adelanto_pendiente', 'procesando'];
      if (convActual && !ESTADOS_PRIORITARIOS.includes(convActual.estado) && !convActual.handoff_humano) {
        await helpers.httpRequest({
          method: 'PATCH',
          url: `${SUPABASE_URL}/rest/v1/consultorio_conversaciones`,
          qs: { telefono_wa: `eq.${formatPhone(paciente.telefono_wa)}` },
          headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
          body: JSON.stringify({
            estado: 'respuesta_reminder',
            contexto: {
              turnoId: turno.id,
              profesionalId: turno.profesional_id,
              profesionalNombre: nombreMedico,
              fechaDisplay,
              horaDisplay
            },
            updated_at: new Date().toISOString()
          })
        });
      }
    } catch(e) { /* no bloquear si falla el update de conv */ }
    enviados++;
  } catch(e) {
    fallidos++;
    await alertTelegram(`⚠️ WF-REMINDER fallo\nPhone: ${paciente.telefono_wa}\nError: ${e.message}`);
  }
}

if (enviados > 0 || fallidos > 0) {
  await alertTelegram(`📅 WF-REMINDER: ${enviados} recordatorio(s) para mañana ${tomorrowART.toISOString().slice(0,10)}${fallidos > 0 ? '. ⚠️ ' + fallidos + ' fallido(s)' : ' ✅'}`);
}

return [{ json: { action: 'reminders_sent', enviados, fallidos, fecha: tomorrowART.toISOString().slice(0, 10) } }];

